import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuthStore } from '@/store/useAuthStore'

// Globale Rangliste-Komponente — wird in Stats.tsx eingebettet.
//
// Lädt parallel:
//   - get_leaderboard(50) RPC: Top-50
//   - get_my_leaderboard_rank() RPC: eigene Position (auch wenn außerhalb Top-50)
//
// Falls eigene Position > 50, wird der eigene Eintrag separat unter der Liste
// gezeigt mit visueller Trennung "...". Ist sie innerhalb Top-50, wird der
// eigene Row in der Liste nur farblich hervorgehoben.

type LeaderboardRow = {
  user_id: string
  display_name: string
  avatar_emoji: string
  rank: string
  level: number
  virag_xp: number
  pos: number
}

type MyRank = LeaderboardRow & { total_players: number }

const TOP_N = 50

export function Leaderboard() {
  const { user } = useAuthStore()
  const [top, setTop] = useState<LeaderboardRow[] | null>(null)
  const [me, setMe] = useState<MyRank | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      const [topRes, meRes] = await Promise.all([
        supabase.rpc('get_leaderboard', { p_limit: TOP_N }),
        user ? supabase.rpc('get_my_leaderboard_rank') : Promise.resolve({ data: null, error: null })
      ])

      if (cancelled) return
      if (topRes.error) { setError(topRes.error.message); return }

      setTop((topRes.data ?? []) as LeaderboardRow[])

      const meRow = ((meRes.data ?? []) as MyRank[])[0]
      setMe(meRow ?? null)
    }

    void load()
    return () => { cancelled = true }
  }, [user])

  if (error) {
    return (
      <div style={{ background: 'var(--white)', border: '2px solid var(--red)', borderRadius: 12, padding: '0.85rem', fontSize: '0.85rem', color: 'var(--red)' }}>
        ⚠ {error}
      </div>
    )
  }

  if (!top) {
    return <div style={{ opacity: 0.55, fontSize: '0.85rem' }}>Wird geladen…</div>
  }

  if (top.length === 0) {
    return (
      <div style={{ background: 'var(--white)', border: '2px dashed rgba(0,0,0,0.15)', borderRadius: 12, padding: '1rem', fontSize: '0.85rem', opacity: 0.7, textAlign: 'center' }}>
        Noch niemand auf der Rangliste — sammle XP, dann erscheinst du hier.
      </div>
    )
  }

  const myInTop = me && top.some((r) => r.user_id === me.user_id)

  return (
    <div
      style={{
        background: 'var(--white)',
        border: '2px solid var(--green)',
        borderRadius: 14,
        boxShadow: 'var(--shadow-card)',
        overflow: 'hidden'
      }}
    >
      <div style={{ display: 'flex', flexDirection: 'column' }}>
        {top.map((row) => (
          <Row key={row.user_id} row={row} highlighted={row.user_id === user?.id} />
        ))}
      </div>

      {/* Eigene Position separat anzeigen falls außerhalb Top-N */}
      {me && !myInTop && (
        <>
          <div style={{ textAlign: 'center', fontSize: '0.85rem', opacity: 0.4, padding: '0.4rem' }}>···</div>
          <Row row={me} highlighted />
        </>
      )}

      {me && (
        <div
          style={{
            background: 'rgba(62, 90, 10, 0.06)',
            borderTop: '1px solid rgba(0,0,0,0.06)',
            padding: '0.55rem 0.85rem',
            fontSize: '0.78rem',
            opacity: 0.75,
            textAlign: 'center'
          }}
        >
          Position {me.pos} von {me.total_players} · {me.virag_xp} XP
        </div>
      )}
    </div>
  )
}

function Row({ row, highlighted }: { row: LeaderboardRow; highlighted: boolean }) {
  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: '40px 32px 1fr auto',
        gap: 10,
        padding: '0.55rem 0.85rem',
        alignItems: 'center',
        background: highlighted ? 'rgba(200, 21, 10, 0.08)' : 'transparent',
        borderBottom: '1px solid rgba(0,0,0,0.04)',
        fontWeight: highlighted ? 700 : 400
      }}
    >
      <PositionBadge position={Number(row.pos)} highlighted={highlighted} />
      <div style={{ fontSize: '1.4rem', textAlign: 'center', lineHeight: 1 }}>{row.avatar_emoji}</div>
      <div style={{ minWidth: 0 }}>
        <div style={{ fontFamily: 'Georgia, serif', fontSize: '0.95rem', color: highlighted ? 'var(--red)' : 'inherit', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
          {row.display_name}
        </div>
        <div style={{ fontSize: '0.7rem', opacity: 0.65, marginTop: 1 }}>
          {row.rank} · Level {row.level}
        </div>
      </div>
      <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '0.95rem', color: highlighted ? 'var(--red)' : 'var(--green)' }}>
        {row.virag_xp.toLocaleString('de-DE')}
      </div>
    </div>
  )
}

function PositionBadge({ position, highlighted }: { position: number; highlighted: boolean }) {
  const isTop3 = position <= 3
  const medal = position === 1 ? '🥇' : position === 2 ? '🥈' : position === 3 ? '🥉' : null

  return (
    <div
      style={{
        fontSize: isTop3 ? '1.15rem' : '0.85rem',
        textAlign: 'center',
        opacity: highlighted || isTop3 ? 1 : 0.55,
        fontVariantNumeric: 'tabular-nums',
        fontWeight: 700,
        color: highlighted ? 'var(--red)' : 'inherit',
        lineHeight: 1
      }}
    >
      {medal ?? `#${position}`}
    </div>
  )
}
