import { useEffect, useState } from 'react'
import { useAuthStore } from '@/store/useAuthStore'
import { supabase } from '@/lib/supabase'
import { Header } from '@/components/Header'
import { BottomNav } from '@/components/BottomNav'
import { Heatmap } from '@/components/Heatmap'
import { Leaderboard } from '@/components/Leaderboard'
import { progressInLevel, rankFromLevel } from '@/lib/levels'

// Stats-Page mit Heatmap, KPI-Karten und Level-Progress.

type Aggregate = {
  totalXp: number
  totalReviews: number
  correctReviews: number
  productionMastered: number
  uniqueDays: number
  daily: Record<string, number>
  achievements: Array<{ icon: string; title: string; description: string; unlocked_at: string }>
}

export default function Stats() {
  const { user } = useAuthStore()
  const [agg, setAgg] = useState<Aggregate | null>(null)
  const [profile, setProfile] = useState<{ level: number; rank: string; daily_goal_xp: number } | null>(null)

  useEffect(() => {
    if (!user) return
    let cancelled = false

    async function load() {
      const [{ data: xp }, { data: srs }, { data: ach }, { data: prof }] = await Promise.all([
        supabase.from('xp_events').select('xp_amount, created_at').eq('user_id', user!.id).eq('app', 'virag'),
        supabase.from('srs_medical').select('total_reviews, correct_reviews, production_mastered_at').eq('user_id', user!.id),
        supabase
          .from('user_achievements')
          .select('unlocked_at, achievements:achievement_id(icon_emoji, title_de, description_de)')
          .eq('user_id', user!.id)
          .order('unlocked_at', { ascending: false }),
        supabase.from('profiles').select('level, rank, daily_goal_xp, app_xp').eq('id', user!.id).single()
      ])

      if (cancelled) return

      const xpRows = (xp ?? []) as Array<{ xp_amount: number; created_at: string }>
      const totalXp = xpRows.reduce((s, r) => s + (r.xp_amount ?? 0), 0)
      const daily: Record<string, number> = {}
      for (const r of xpRows) {
        const day = r.created_at.slice(0, 10)
        daily[day] = (daily[day] ?? 0) + (r.xp_amount ?? 0)
      }

      const srsRows = (srs ?? []) as Array<{ total_reviews: number; correct_reviews: number; production_mastered_at: string | null }>
      const totalReviews = srsRows.reduce((s, r) => s + (r.total_reviews ?? 0), 0)
      const correctReviews = srsRows.reduce((s, r) => s + (r.correct_reviews ?? 0), 0)
      const productionMastered = srsRows.filter((r) => r.production_mastered_at).length

      type AchRow = { unlocked_at: string; achievements: { icon_emoji: string | null; title_de: string; description_de: string | null } | { icon_emoji: string | null; title_de: string; description_de: string | null }[] | null }
      const achievements = ((ach ?? []) as AchRow[]).map((r) => {
        const a = Array.isArray(r.achievements) ? r.achievements[0] : r.achievements
        return {
          icon: a?.icon_emoji ?? '🏆',
          title: a?.title_de ?? '',
          description: a?.description_de ?? '',
          unlocked_at: r.unlocked_at
        }
      })

      setAgg({
        totalXp,
        totalReviews,
        correctReviews,
        productionMastered,
        uniqueDays: Object.keys(daily).length,
        daily,
        achievements
      })

      if (prof) {
        const p = prof as { level: number | null; rank: string | null; daily_goal_xp: number | null; app_xp: Record<string, number> | null }
        setProfile({
          level: p.level ?? 1,
          rank: p.rank ?? 'Medikus I',
          daily_goal_xp: p.daily_goal_xp ?? 100
        })
      }
    }

    void load()
    return () => { cancelled = true }
  }, [user])

  const correctPct = agg && agg.totalReviews > 0 ? Math.round((agg.correctReviews / agg.totalReviews) * 100) : null
  const lvl = profile ? progressInLevel(agg?.totalXp ?? 0) : null
  const nextRank = profile && lvl ? rankFromLevel(lvl.level + 1) : null

  return (
    <div style={{ minHeight: '100vh', background: 'var(--cream)', paddingBottom: 90 }}>
      <Header />
      <main className="app-container">
        <h1 className="app-name" style={{ color: 'var(--red)', margin: 0, fontSize: '1.45rem' }}>
          Statistiken 📊
        </h1>

        {!agg && <div style={{ opacity: 0.55, fontSize: '0.9rem' }}>Wird geladen…</div>}
        {agg && (
          <>
            {/* Level-Progress */}
            {lvl && (
              <Card color="var(--red)">
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', opacity: 0.7, marginBottom: 4 }}>
                  <span>Level {lvl.level} · {profile?.rank}</span>
                  {nextRank && nextRank.rankHu !== profile?.rank && <span>→ {nextRank.rankHu}</span>}
                </div>
                <div style={{ height: 10, background: 'rgba(0,0,0,0.08)', borderRadius: 999, overflow: 'hidden', marginBottom: 6 }}>
                  <div style={{ width: `${lvl.pct * 100}%`, height: '100%', background: 'var(--header-stripe)', borderRadius: 999, transition: 'width 400ms' }} />
                </div>
                <div style={{ fontSize: '0.78rem', opacity: 0.7, textAlign: 'right' }}>
                  {lvl.xpInto} / {lvl.xpToNext} XP
                </div>
              </Card>
            )}

            {/* KPIs */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.7rem' }}>
              <Card color="var(--red)">
                <Big>{agg.totalXp}</Big>
                <Label>Total Virág-XP</Label>
              </Card>
              <Card color="var(--green)">
                <Big>{agg.totalReviews}</Big>
                <Label>Karten-Reviews</Label>
              </Card>
              <Card color="var(--orange)">
                <Big>{correctPct === null ? '—' : `${correctPct}%`}</Big>
                <Label>Richtig-Quote</Label>
              </Card>
              <Card color="var(--lg)">
                <Big>{agg.uniqueDays}</Big>
                <Label>Aktive Tage</Label>
              </Card>
              <Card color="var(--yellow)">
                <Big>{agg.productionMastered}</Big>
                <Label>🏆 Production-Mastered</Label>
              </Card>
              <Card color="var(--green)">
                <Big>{agg.achievements.length}/15</Big>
                <Label>Achievements</Label>
              </Card>
            </div>

            {/* Heatmap */}
            <h2 style={subheading}>Aktivität (12 Wochen)</h2>
            <Card color="var(--green)" pad="0.85rem">
              <Heatmap daily={agg.daily} />
            </Card>

            {/* Globale Rangliste */}
            <h2 style={subheading}>Rangliste 🏆</h2>
            <Leaderboard />

            {/* Achievements */}
            <h2 style={subheading}>Achievements</h2>
            {agg.achievements.length === 0 ? (
              <div style={{ opacity: 0.55, fontSize: '0.85rem' }}>Noch keins freigeschaltet — beim nächsten Lernschritt los!</div>
            ) : (
              <div style={{ display: 'grid', gap: 8 }}>
                {agg.achievements.map((a) => (
                  <div key={a.title} style={{ background: 'var(--white)', border: '2px solid var(--yellow)', borderRadius: 12, padding: '0.7rem 0.9rem', boxShadow: 'var(--shadow-card)', display: 'flex', alignItems: 'center', gap: 10 }}>
                    <span style={{ fontSize: '1.6rem' }}>{a.icon}</span>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, color: 'var(--red)', fontSize: '0.95rem' }}>{a.title}</div>
                      <div style={{ fontSize: '0.78rem', opacity: 0.7 }}>{a.description}</div>
                    </div>
                    <div style={{ fontSize: '0.7rem', opacity: 0.5 }}>{new Date(a.unlocked_at).toLocaleDateString('de-DE')}</div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}
      </main>
      <BottomNav />
    </div>
  )
}

const subheading: React.CSSProperties = {
  fontFamily: 'Georgia, serif',
  fontSize: '0.85rem',
  letterSpacing: '1px',
  textTransform: 'uppercase',
  opacity: 0.6,
  margin: '0.5rem 0 0'
}

function Card({ color, children, pad = '1rem' }: { color: string; children: React.ReactNode; pad?: string }) {
  return (
    <div style={{ background: 'var(--white)', border: `2px solid ${color}`, borderRadius: 14, padding: pad, boxShadow: 'var(--shadow-card)' }}>
      {children}
    </div>
  )
}

function Big({ children }: { children: React.ReactNode }) {
  return <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1.8rem', color: 'var(--red)', textAlign: 'center' }}>{children}</div>
}

function Label({ children }: { children: React.ReactNode }) {
  return <div style={{ fontSize: '0.78rem', opacity: 0.7, marginTop: 2, textAlign: 'center' }}>{children}</div>
}
