// 12-Wochen-Heatmap (84 Zellen, 7 Tage × 12 Wochen) mit Folk-Farbskala.
//
// Input: tägliche XP-Werte als ISO-Date-Map. Cell-Farbe nach 5 Stufen:
//   0 XP        → cream / sehr blass
//   1-50        → gelb mit niedriger Opacity
//   51-150      → orange
//   151-300     → rot
//   >300        → kräftig grün (Tagesziel-erreicht-Vibe)

type Props = {
  /** ISO-date string (YYYY-MM-DD) → XP an dem Tag */
  daily: Record<string, number>
  weeks?: number
}

function levelColor(xp: number): string {
  if (xp === 0) return 'rgba(0,0,0,0.06)'
  if (xp < 50)  return 'rgba(200, 160, 0, 0.35)'   // yellow-ish
  if (xp < 150) return 'rgba(217, 107, 16, 0.55)'  // orange
  if (xp < 300) return 'rgba(200, 21, 10, 0.65)'   // red
  return 'rgba(62, 90, 10, 0.85)'                   // green
}

const DAYS_DE = ['Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa', 'So']

export function Heatmap({ daily, weeks = 12 }: Props) {
  // Wir bauen ein Grid: rows = 7 Wochentage (Mo–So), cols = `weeks` Wochen
  // Letzte Spalte = aktuelle Woche, Zellen für künftige Tage in der aktuellen
  // Woche bleiben grau-leer.

  const today = new Date()
  // Berechne den Montag der aktuellen Woche (UTC-naive, am Tag)
  const dow = (today.getDay() + 6) % 7  // Mo=0..So=6
  const monday = new Date(today)
  monday.setHours(0, 0, 0, 0)
  monday.setDate(monday.getDate() - dow)

  const cells: Array<{ date: string; xp: number; future: boolean }> = []
  // Wir füllen Spalte für Spalte (Woche), pro Spalte Mo→So
  for (let w = weeks - 1; w >= 0; w--) {
    for (let d = 0; d < 7; d++) {
      const cellDate = new Date(monday)
      cellDate.setDate(cellDate.getDate() - w * 7 + d)
      const iso = cellDate.toISOString().slice(0, 10)
      const xp = daily[iso] ?? 0
      const future = cellDate > today
      cells.push({ date: iso, xp, future })
    }
  }

  // Cells sind in row-major Reihenfolge (woche × tag).
  // Wir rendern als CSS-Grid mit gridTemplateColumns: repeat(weeks, 1fr).
  // Die Reihenfolge der cells ist (week=oldest..newest), in jeder week tag=Mo..So.
  // Für ein typisches Heatmap-Layout (rows=days, cols=weeks) brauchen wir die
  // Cells transponiert. Lass uns lieber explizit über Zeile/Spalte iterieren.

  return (
    <div style={{ display: 'flex', gap: 6, alignItems: 'flex-start' }}>
      {/* Tag-Labels links */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 4, paddingTop: 14 }}>
        {DAYS_DE.map((d, i) => (
          <span key={d} style={{ height: 14, fontSize: '0.6rem', opacity: 0.5, lineHeight: '14px' }}>
            {i % 2 === 0 ? d : ''}
          </span>
        ))}
      </div>

      {/* Heatmap-Grid */}
      <div style={{ flex: 1, overflowX: 'auto' }}>
        <div style={{ display: 'grid', gridTemplateColumns: `repeat(${weeks}, 1fr)`, gridTemplateRows: 'repeat(7, 14px)', gap: 4, minWidth: weeks * 18 }}>
          {Array.from({ length: 7 * weeks }).map((_, idx) => {
            const day = idx % 7
            const week = Math.floor(idx / 7)
            // mappe (day, week) zu cells-index (week-major Mo..So order)
            // unsere cells: für w in [weeks-1..0]: for d in [0..6]
            // d.h. cells[i] mit i = (weeks-1-w) * 7 + d
            // Wir wollen day=d, week=w_visible (0=oldest..weeks-1=newest)
            // → cells-index = (weeks - 1 - w_visible) * 7 + d
            // Aber unser CSS-grid läuft column-major (oder row-major?)
            // Mit grid-auto-flow=row (default) füllt es Reihen-by-Reihe.
            // Aber wir wollen Reihen=Tage, Spalten=Wochen → das matcht column-major.
            // Wir setzen explizit gridRow und gridColumn:
            const w_visible = week
            const cellIdx = (weeks - 1 - (weeks - 1 - w_visible)) * 7 + day
            const c = cells[cellIdx]
            return (
              <div
                key={idx}
                title={c?.future ? '' : `${c?.date}: ${c?.xp ?? 0} XP`}
                style={{
                  gridRow: day + 1,
                  gridColumn: week + 1,
                  width: '100%',
                  height: 14,
                  borderRadius: 3,
                  background: c?.future ? 'transparent' : levelColor(c?.xp ?? 0),
                  border: c?.future ? '1px dashed rgba(0,0,0,0.05)' : 'none'
                }}
              />
            )
          })}
        </div>

        {/* Legende */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 4, fontSize: '0.65rem', opacity: 0.55, marginTop: 6, justifyContent: 'flex-end' }}>
          <span>weniger</span>
          {[0, 30, 100, 200, 350].map((xp) => (
            <span key={xp} style={{ width: 12, height: 12, borderRadius: 3, background: levelColor(xp) }} />
          ))}
          <span>mehr</span>
        </div>
      </div>
    </div>
  )
}
